import React from 'react';
import './Common.css';

function LoadingSpinner({
  size = 'md',
  label = '불러오는 중...',
  fullScreen = false,
  overlay = false,
  className = '',
}) {
  const wrapperClassName = [
    'common-loading',
    `common-loading--${size}`,
    fullScreen ? 'common-loading--fullscreen' : '',
    overlay ? 'common-loading--overlay' : '',
    className,
  ]
    .filter(Boolean)
    .join(' ');

  return (
    <div
      className={wrapperClassName}
      role="status"
      aria-live="polite"
      aria-label={label}
    >
      <div className="common-loading__content">
        <div className="common-spinner" aria-hidden="true">
          <span className="common-spinner__ring common-spinner__ring--one" />
          <span className="common-spinner__ring common-spinner__ring--two" />
          <span className="common-spinner__core" />
        </div>

        <div className="common-loading__text">
          <strong>{label}</strong>
          <div className="common-loading__dots" aria-hidden="true">
            <span />
            <span />
            <span />
          </div>
        </div>
      </div>
    </div>
  );
}

export default LoadingSpinner;
